export const POST_QUIZ_BY_WEEK = {
  1: [
    { q:"A 68-year-old woman on lisinopril, furosemide, and NSAIDs presents with Cr rising from 1.1 to 2.4 over 3 days. UNa 8, FEUrea 22%, bland sediment. Most likely mechanism?",
      choices:["ATN from NSAID toxicity","Pre-renal AKI: NSAIDs + ACEi impair renal autoregulation","AIN from NSAID","Post-renal obstruction"], answer:1,
      explanation:"NSAIDs block prostaglandin-mediated afferent dilation while ACEi block efferent constriction → 'double hit' on renal perfusion. Low UNa and FEUrea <35% confirm pre-renal physiology. This is a classic board question." },
    { q:"Cystatin C is most useful for estimating GFR when:",
      choices:["The patient has normal muscle mass","Creatinine-based eGFR may be inaccurate (extremes of muscle mass, amputees, vegetarian diet)","The patient has AKI","The patient is on dialysis"], answer:1,
      explanation:"Cystatin C is produced by all nucleated cells (not muscle-dependent), so it's useful when creatinine is unreliable: bodybuilders, amputees, sarcopenia, vegetarians, etc." },
    { q:"A patient develops AKI on day 3 of vancomycin. Urine shows WBC casts, eosinophiluria, and new rash. Most likely diagnosis?",
      choices:["ATN","Pre-renal AKI","Acute interstitial nephritis","Post-infectious GN"], answer:2,
      explanation:"Classic AIN triad: fever, rash, eosinophilia (only present ~30%). WBC casts and eosinophiluria support it. Vancomycin is a common culprit. Management: stop the drug ± steroids." },
    { q:"Which creatinine trajectory pattern suggests acute-on-chronic kidney disease?",
      choices:["Cr rising from 0.8 to 3.0 over 2 days with prior normal Cr","Cr rising from 2.1 to 4.5 over 3 days with baseline Cr of 2.0","Cr stable at 1.2 for 6 months","Cr of 5.0 with bilateral small kidneys on ultrasound"], answer:1,
      explanation:"Baseline Cr of 2.0 (already CKD) now acutely rising → acute-on-chronic. Option D is chronic. Reviewing ALL prior creatinine values is essential to establish the trajectory." },
    { q:"Urine electrolytes show FENa 3.5% in a patient with AKI. However, they received furosemide 4 hours ago. How should you interpret this?",
      choices:["FENa is valid — this is ATN","FENa is unreliable — check FEUrea instead","FENa is always valid regardless of diuretics","Order a 24-hour urine collection"], answer:1,
      explanation:"Loop diuretics force sodium excretion, making FENa falsely elevated. FEUrea is LESS affected by diuretics and is generally the better test in diuretic-exposed patients (<35% pre-renal, >50% ATN) \u2014 but it is not fully immune. A 2020 prospective cohort (Diskin et al, AJKD) showed loop diuretics meaningfully shifted FEUrea values and reclassified roughly a quarter of patients across the 35% cutoff, so interpret FEUrea in context (clinical picture, sediment, response to volume)." },
    { q:"You see waxy casts on urine microscopy. This suggests:",
      choices:["Acute process, likely ATN","Chronic kidney disease with long-standing tubular stasis","Active glomerulonephritis","Normal finding"], answer:1,
      explanation:"Waxy casts are 'old' granular casts — they indicate prolonged tubular stasis seen in advanced CKD. They suggest chronicity, not an acute process." },
    { q:"A 64-year-old woman with hypertension has a steady eGFR of 52 and UACR of 180 mg/g on two visits 4 months apart; UA is otherwise bland. Which statement about her CKD stage is most accurate?",
      choices:["She does not have CKD because her eGFR is >45","She is G3a A2 — her albuminuria adds independent prognostic risk beyond eGFR alone","She is G2 A2 because her eGFR is >45","She is G3a A3 — any albuminuria ≥30 is category A3"], answer:1,
      explanation:"KDIGO stages CKD on two axes: eGFR (G1 ≥90, G2 60–89, G3a 45–59, G3b 30–44, G4 15–29, G5 <15) and albuminuria (A1 <30, A2 30–300, A3 >300 mg/g). eGFR 52 → G3a; UACR 180 → A2. At the same eGFR, moving from A1 to A2 roughly doubles cardiovascular and ESKD risk — albuminuria is not just a marker, it's an independent driver of therapy (RAAS blockade, SGLT2i, finerenone)." },
  ],
  2: [
    { q:"A patient with SIADH (Na⁺ 118) is treated with normal saline. After 12 hours, Na⁺ is 132. What is the immediate concern?",
      choices:["Hypernatremia","Osmotic demyelination syndrome from overcorrection","Cerebral edema","Pulmonary edema"], answer:1,
      explanation:"Na⁺ rose 14 mEq/L in 12h — far exceeding the 6-8 mEq/24h limit. Risk of ODS. In SIADH, NS can worsen hyponatremia or cause unpredictable overcorrection when ADH effect wanes. Consider D5W to re-lower Na⁺ and desmopressin to prevent further water excretion." },
    { q:"A patient with K⁺ of 7.2 receives calcium gluconate, insulin/dextrose, and albuterol but K⁺ remains 6.9 after 2 hours. ECG shows progressive QRS widening. Next step?",
      choices:["Repeat insulin/dextrose","Kayexalate","Emergent hemodialysis","IV sodium bicarbonate"], answer:2,
      explanation:"This is refractory hyperkalemia (the 'E' in AEIOU) — medical management has failed and ECG shows worsening toxicity. Emergent dialysis is the definitive treatment to remove K⁺." },
    { q:"ABG: pH 7.52, pCO₂ 48, HCO₃⁻ 38. What is the primary disorder?",
      choices:["Respiratory alkalosis","Metabolic alkalosis with respiratory compensation","Respiratory acidosis with metabolic compensation","Mixed alkalosis"], answer:1,
      explanation:"pH >7.45 = alkalosis. High HCO₃⁻ = metabolic cause. Expected pCO₂ compensation: 0.7 × ΔHCO₃⁻ + 40 ± 2 = 0.7(14)+40 = 49.8 ± 2. Actual 48 fits. Common causes: vomiting, NG suction, diuretics." },
    { q:"You calculate the serum anion gap = 24 (normal 12). The delta-delta ratio is 1.8. This suggests:",
      choices:["Pure AG metabolic acidosis","AG acidosis + metabolic alkalosis","AG acidosis + non-AG acidosis","Triple acid-base disorder"], answer:0,
      explanation:"Delta-delta (ΔAG/ΔHCO₃⁻) between 1-2 indicates a pure AG metabolic acidosis. >2 suggests a concurrent metabolic alkalosis raising the HCO₃⁻ higher than expected. <1 suggests a concurrent non-AG acidosis. 1.8 falls in the pure AGMA range, though borderline — clinical context matters." },
    { q:"Lactated Ringer's is preferred over normal saline in large-volume resuscitation because:",
      choices:["It has more sodium","It prevents hyperchloremic metabolic acidosis","It costs less","It is better for hyperkalemic patients"], answer:1,
      explanation:"NS has 154 mEq/L of Cl⁻ (supraphysiologic). Large volumes cause hyperchloremic non-AG metabolic acidosis and may reduce renal blood flow. LR has 109 Cl⁻ (physiologic) and SMART/SALT-ED showed better kidney outcomes with balanced crystalloids. The old 'avoid LR in hyperkalemia' rule is outdated: LR's 4 mEq/L K⁺ is much lower than serum K⁺ in a hyperkalemic patient, and modern trial data in hyperkalemic/AKI subgroups show balanced crystalloids are NOT worse than NS. Balanced fluids should be the default across most clinical contexts." },
    { q:"Secondary hyperparathyroidism in CKD is driven by:",
      choices:["High calcium, low phosphorus","Low calcitriol, high phosphorus, low calcium","High calcitriol, high calcium","Autonomous parathyroid adenoma"], answer:1,
      explanation:"CKD → ↓1-alpha hydroxylase → ↓calcitriol → ↓Ca²⁺ absorption. Also: ↓phosphorus excretion → hyperphosphatemia. Both stimulate PTH release. Autonomous adenoma = tertiary hyperPTH." },
    { q:"A 52-year-old man with DKA presents obtunded with glucose 720, measured Na⁺ 128, K⁺ 5.4, and HCO₃⁻ 8. Before deciding he is truly hyponatremic, what is his approximate corrected serum Na⁺?",
      choices:["128 — no correction needed","About 132","About 138","About 148"], answer:2,
      explanation:"Hyperglycemia pulls intracellular water into the vascular space, producing a translocational (dilutional) hyponatremia. The Katz correction adds 1.6 mEq/L for every 100 mg/dL glucose above 100: (720 − 100)/100 × 1.6 ≈ 9.9, so corrected Na⁺ ≈ 138. Always correct before labeling a hyperglycemic patient hyponatremic — 'hyponatremia' in DKA is usually an artifact that resolves with insulin-driven glucose lowering. (The Hillier 2.4 factor is sometimes used for glucose >400 and would give ~143, but 1.6 is the standard teaching.)" },
  ],
  3: [
    { q:"A 25-year-old presents with edema, proteinuria 8g/day, and normal complement levels. Renal biopsy shows podocyte effacement on EM with no immune deposits. Diagnosis?",
      choices:["Membranous nephropathy","Minimal change disease","FSGS","IgA nephropathy"], answer:1,
      explanation:"Nephrotic syndrome in a young adult + normal complement + podocyte foot process effacement + NO immune deposits on IF/EM = minimal change disease. It's the most common nephrotic syndrome in children and responds well to steroids." },
    { q:"A patient with lupus has proteinuria, hematuria, low C3/C4, and positive anti-dsDNA. Biopsy shows 'wire loop' deposits. Most likely class of lupus nephritis?",
      choices:["Class II (mesangial)","Class III (focal proliferative)","Class IV (diffuse proliferative)","Class V (membranous)"], answer:2,
      explanation:"Class IV (diffuse proliferative) is the most severe and common form requiring aggressive treatment. 'Wire loops' are subendothelial deposits seen on light microscopy, with 'full house' IF pattern. KDIGO 2024 lists several initial regimens — glucocorticoids plus (a) MPAA (MMF/EC-MPS) alone, (b) low-dose IV cyclophosphamide (Euro-Lupus), (c) belimumab + MPAA or CYC (BLISS-LN), or (d) MPAA + a CNI (voclosporin per AURORA-1, or tacrolimus) when kidney function is not severely impaired. Obinutuzumab (Gazyva, anti-CD20) received FDA approval for active lupus nephritis in October 2025 based on the REGENCY trial — it is now a real option to add to MMF + steroids, though post-dates the KDIGO 2024 guideline text. Individualize choice by proteinuria, eGFR, tolerability, fertility, and access." },
    { q:"CREDENCE and DAPA-CKD trials demonstrated that SGLT2 inhibitors reduce the primary composite endpoint of CKD progression by approximately:",
      choices:["10-15%","20-25%","30-40%","50-60%"], answer:2,
      explanation:"Both CREDENCE (canagliflozin) and DAPA-CKD (dapagliflozin) showed ~30-39% relative risk reduction in the composite kidney endpoint. This is practice-changing: SGLT2i are now standard of care in proteinuric CKD." },
    { q:"An ACEi is started for proteinuric CKD. Creatinine rises from 1.4 to 1.7 (21% increase). Appropriate next step?",
      choices:["Stop the ACEi immediately","Continue ACEi — up to 30% Cr rise is expected and acceptable","Switch to an ARB","Add an NSAID for renal protection"], answer:1,
      explanation:"ACEi/ARBs dilate the efferent arteriole → GFR drops slightly → Cr rises. A rise up to 30% is expected and actually indicates the drug is working (reducing intraglomerular pressure). Stop only if Cr rises >30% or hyperkalemia develops." },
    { q:"What is the practical clinic target blood pressure many providers aim for in CKD with albuminuria (recognizing that KDIGO now favors a stricter SBP goal when tolerated)?",
      choices:["<150/90","<140/90","<130/80","<120/70"], answer:2,
      explanation:"KDIGO's current BP guidance for CKD targets standardized office SBP <120 mmHg when tolerated (SPRINT-style, using unattended/automated technique). In day-to-day clinic practice with conventional cuff measurements, <130/80 remains the most commonly used target for CKD with albuminuria. Both numbers can be 'right' depending on which measurement technique and guideline framing you use \u2014 be explicit with patients about which target you're using and how BP is being measured." },
    { q:"Post-infectious glomerulonephritis typically occurs ___ after Group A Strep infection and shows ___ complement levels.",
      choices:["1-3 weeks after; low C3","Simultaneously; normal complement","1-3 weeks after; low C4 only","6 months after; low C3 and C4"], answer:0,
      explanation:"PIGN has a latent period of 1-3 weeks (vs IgA = synpharyngitic). Classic finding: low C3 (alternative pathway activation) with normal C4. C3 normalizes in 6-8 weeks." },
  ],
  4: [
    { q:"A dialysis patient missed two sessions and presents with K⁺ 7.8, pH 7.18, BUN 120, and severe pulmonary edema. He has an AV fistula. Best immediate approach?",
      choices:["Medical management only","Urgent hemodialysis","Peritoneal dialysis","Continuous renal replacement therapy (CRRT)"], answer:1,
      explanation:"Multiple indications (AEIOU): refractory K⁺, acidosis, overload, uremia. With a functioning fistula, urgent HD is the fastest way to correct all of these. CRRT is for hemodynamically unstable ICU patients." },
    { q:"What is the most common cause of death in dialysis patients?",
      choices:["Infection","Cardiovascular disease","Malignancy","Hyperkalemia"], answer:1,
      explanation:"Cardiovascular disease accounts for ~40-50% of deaths in dialysis patients. Accelerated atherosclerosis, volume overload, and uremic cardiomyopathy all contribute. This is why CV risk factor management is critical." },
    { q:"A transplant patient on tacrolimus, mycophenolate, and prednisone develops rising creatinine 3 months post-transplant. Biopsy shows tubulitis and interstitial inflammation. Diagnosis?",
      choices:["Calcineurin inhibitor toxicity","Acute cellular rejection","BK virus nephropathy","Recurrent native disease"], answer:1,
      explanation:"Tubulitis (lymphocyte invasion of tubular epithelium) + interstitial inflammation = acute cellular rejection (T-cell mediated). First-line treatment is pulse IV methylprednisolone. CNI toxicity shows arteriolar changes, not tubulitis." },
    { q:"A 45-year-old woman with her third calcium-oxalate kidney stone in 4 years has a 24-hour urine showing low urinary citrate and normal urinary calcium. Which intervention has the strongest evidence for preventing recurrence in her?",
      choices:["Dietary calcium restriction","Increased fluid intake to achieve urine volume >2.5 L/day plus potassium citrate","Daily allopurinol","Low-protein, high-sodium diet"], answer:1,
      explanation:"The cornerstone of stone prevention is hydration — target urine volume >2.5 L/day. Hypocitraturia is a major risk factor because citrate chelates urinary calcium and inhibits crystallization; potassium citrate both replaces citrate and alkalinizes urine. Dietary calcium RESTRICTION is a classic trap — it increases oxalate absorption and worsens calcium-oxalate stones; normal dietary calcium (1,000–1,200 mg/day) with meals is protective. Low-sodium (not high) and moderate-protein diets also reduce urinary calcium." },
    { q:"Contrast-induced nephropathy (CIN) is best prevented by:",
      choices:["N-acetylcysteine before the procedure","IV isotonic saline hydration before and after","Furosemide to increase urine output","Avoiding all contrast in CKD patients"], answer:1,
      explanation:"IV isotonic fluid (NS or bicarb) before and after contrast is the best-studied prevention. NAC has NOT been shown to be beneficial in recent trials (PRESERVE, 2018). Don't withhold necessary contrast from CKD patients — just hydrate and use low-osmolar contrast." },
  ],
};

