// ═══════════════════════════════════════════════════════════════════════
//  Weekly Quizzes — 10 questions per week (will be expanded in Phase 2)
// ═══════════════════════════════════════════════════════════════════════

export const WEEKLY_QUIZZES = {
  1: [
    { q:"A 72-year-old man admitted with pneumonia has baseline Cr 1.0. On day 2, Cr is 1.4. Does he have AKI?",
      choices:["No — creatinine is still normal","Yes — Cr rose ≥0.3 mg/dL within 48h","Yes — Cr rose ≥1.5× baseline","Cannot determine without UOP"], answer:1,
      explanation:"KDIGO Stage 1: ≥0.3 mg/dL rise in 48h. His Cr rose 0.4 in 2 days — even though 1.4 is 'normal' range. Don't be fooled by the absolute number." },
    { q:"A 28-year-old competitive bodybuilder (6'2\", 110 kg, very muscular) has a routine Cr of 1.3 mg/dL. He feels well, BP is 118/72, UA is bland, and cystatin C-based eGFR is 105 mL/min. Which statement best explains the discrepancy?",
      choices:["He has early CKD that cystatin C underestimates","High muscle mass elevates creatinine production, so Cr-based eGFR falsely suggests kidney dysfunction","Cystatin C is unreliable in young adults","He is likely using nephrotoxic supplements"], answer:1,
      explanation:"Creatinine is a byproduct of muscle metabolism, so high muscle mass raises serum Cr without any true GFR decline. Cr-based eGFR underestimates GFR in bodybuilders; cystatin C-based eGFR is more accurate because it is not muscle-dependent. Similar issues occur with amputees, cachexia, and paraplegia." },
    { q:"A 65-year-old with 4 days of vomiting and poor intake is admitted with Cr 2.1 (baseline 1.0). Urine Na is 12, FENa 0.4%, BUN/Cr 28, and UA shows bland sediment. What is the most likely mechanism?",
      choices:["Acute tubular necrosis","Acute interstitial nephritis","Pre-renal azotemia","Urinary obstruction"], answer:2,
      explanation:"Low FENa (<1%), low urine Na, elevated BUN/Cr (>20:1), and bland sediment point to pre-renal physiology — the tubules are working and avidly reabsorbing Na. The kidney itself isn't damaged; it's just underperfused. Volume repletion should reverse the AKI quickly." },
    { q:"A 68-year-old 5 days post-op from aortic surgery with prolonged hypotension has Cr rising from 1.1 to 2.8. FENa is 3%, BUN/Cr is 12, and UA shows numerous dark brown granular casts. Most likely diagnosis?",
      choices:["Glomerulonephritis","Urinary tract infection","Acute tubular necrosis","Pre-renal AKI"], answer:2,
      explanation:"Muddy brown granular casts are the hallmark of ATN — sloughed necrotic tubular epithelial cells trapped in Tamm-Horsfall protein. Ischemic ATN typically follows hypotension, sepsis, or major surgery. FENa is usually >2% because injured tubules can't reabsorb Na." },
    { q:"A 74-year-old with decompensated CHF on furosemide 80 mg IV BID develops AKI (Cr 1.2 → 2.0). Urine Na is 45 and FENa calculates to 2.8%. You suspect pre-renal physiology from over-diuresis. Which test best confirms this?",
      choices:["Repeat urine osmolality","Fractional excretion of urea (FEUrea)","BUN/Cr ratio alone","24-hour urine creatinine clearance"], answer:1,
      explanation:"Loop diuretics force Na excretion and make FENa falsely elevated, mimicking ATN. FEUrea bypasses this because urea handling is not affected by loop diuretics. FEUrea <35% supports pre-renal; >50% supports ATN." },
    { q:"A 62-year-old Black woman is seen in clinic for CKD follow-up. Her Cr is 1.4. Her chart shows an older eGFR calculated with a race coefficient and a newer eGFR without. The newer value is lower. Which equation is now the standard for reporting eGFR?",
      choices:["MDRD with race coefficient","CKD-EPI 2021 (race removed; uses age, sex, Cr)","Cockcroft-Gault","CKD-EPI 2009 with race coefficient"], answer:1,
      explanation:"The CKD-EPI 2021 equation removed the race coefficient to address health equity concerns; it uses age, sex, and creatinine. For greater accuracy, the combined Cr-cystatin C equation is preferred when available. Cockcroft-Gault estimates CrCl, not GFR, and is still used for some FDA drug dosing." },
    { q:"A 24-year-old with pharyngitis 2 weeks ago presents with tea-colored urine, edema, and BP 162/98. Cr is 1.6 (baseline 0.8). UA shows 3+ blood, 2+ protein, and microscopy reveals RBC casts. This finding is pathognomonic for which process?",
      choices:["Nephrolithiasis","Bladder malignancy","Glomerulonephritis","Acute tubular necrosis"], answer:2,
      explanation:"RBC casts form when red cells traverse a damaged glomerular basement membrane and are molded in tubular lumen by Tamm-Horsfall protein. Their presence is specific for glomerulonephritis. In this case, the post-pharyngitis timing suggests post-infectious GN, but the cast itself simply tells you the disease is glomerular." },
    { q:"A 55-year-old oliguric AKI patient has K⁺ 7.2, peaked T-waves, and widening QRS. He has received IV calcium, insulin/D50, and albuterol, but repeat K⁺ is 6.9 and ECG is unchanged. What is the most appropriate next step?",
      choices:["Continue medical management alone","Check potassium in 1 hour before any further action","Initiate emergent dialysis for refractory hyperkalemia","Start low-dose loop diuretic and reassess in 4 hours"], answer:2,
      explanation:"The 'E' in AEIOU (Acidosis, Electrolytes, Ingestions, Overload, Uremia) requires that electrolyte derangement be refractory to medical therapy. Life-threatening hyperkalemia with ongoing ECG changes despite shifting and stabilizing agents meets that bar. Emergent HD removes K⁺; medical management only shifts it temporarily." },
    { q:"You are called to see a 70-year-old man whose Cr jumped from 1.0 to 2.4 overnight. Before calculating FENa, ordering imaging, or starting fluids, what is the FIRST step in your evaluation?",
      choices:["Order a renal biopsy","Bolus 2 L of normal saline empirically","Review prior creatinine trend to establish baseline and tempo","Calculate fractional excretion of sodium"], answer:2,
      explanation:"Every AKI workup starts by defining baseline Cr and how fast the change occurred — this distinguishes acute from acute-on-chronic, and shapes the differential (hours = ischemia/obstruction; days = ATN/AIN; weeks = GN/CKD progression). Jumping to tests or fluids without this context often leads to the wrong diagnosis." },
    { q:"A pharmacist asks you about drug dosing in a 78-year-old with Cr 1.6, weight 52 kg. The drug's package insert specifies renal dose adjustment based on CrCl. Which statement about the Cockcroft-Gault equation is TRUE?",
      choices:["It is the current KDIGO standard for staging CKD","It estimates GFR adjusted for body surface area","It estimates CrCl and is still referenced by the FDA for many drug dosing decisions","It requires cystatin C to calculate"], answer:2,
      explanation:"Cockcroft-Gault estimates CrCl (not GFR) and is not BSA-indexed, so it can differ meaningfully from CKD-EPI eGFR in small or elderly patients. Because original PK studies used CG, many FDA drug labels still cite CG-based CrCl thresholds for dose adjustment. For staging, use CKD-EPI 2021 eGFR." },
    { q:"A 58-year-old man with cirrhosis and ascites develops AKI (Cr 1.1 \u2192 3.2). Urine Na is 5 mEq/L, UA is bland, renal US is normal, and there is no evidence of infection or nephrotoxin exposure. After adequate volume resuscitation with IV albumin and withdrawal of diuretics, the Cr remains 3.0. What is the most likely diagnosis?",
      choices:["Prerenal AKI from volume depletion","Acute tubular necrosis","Hepatorenal syndrome-AKI","Post-renal obstruction"], answer:2,
      explanation:"This patient meets the ICA/ADQI 2024 HRS-AKI criteria: cirrhosis + ascites, AKI with no shock/nephrotoxins/obstruction/GN, and no improvement after adequate volume resuscitation. The 2024 criteria replaced the rigid 48h 1 g/kg/day albumin challenge with clinically adequate volume resuscitation. The very low urine Na (<10) and bland sediment are characteristic but not required. Remember: HRS is a diagnosis of exclusion.",
      topic: "Hepatorenal Syndrome" },
    { q:"A patient undergoes coronary angiography and develops a Cr rise from 1.0 to 1.8 mg/dL 48 hours later. The UA shows few muddy brown casts. Which finding would make you suspect atheroemboli rather than contrast-induced AKI?",
      choices:["Cr rise within 24-48 hours of contrast","Muddy brown casts on UA","Blue-purple discoloration of the toes and peripheral eosinophilia","Return of Cr to baseline within 7 days"], answer:2,
      explanation:"Atheroemboli (cholesterol crystal embolization) presents with livedo reticularis, 'blue toe syndrome,' eosinophilia, and hypocomplementemia \u2014 typically with a delayed onset (days to weeks after angiography). CI-AKI has an early onset (24-48h) and usually recovers within 7 days. Atheroemboli have a much worse prognosis.",
      topic: "Contrast-Associated AKI" },
    { q:"A 25-year-old is found unresponsive after a music festival. CK is 85,000 U/L, K+ is 6.8 mEq/L, Ca\u00b2\u207a is 7.1 mg/dL (low), and urine is dark brown. Urine dipstick is 3+ blood, but microscopy shows <3 RBCs/HPF. What is the most important INITIAL intervention?",
      choices:["IV calcium gluconate for hypocalcemia","IV bicarbonate to alkalinize the urine","Treat the hyperkalemia immediately (calcium gluconate for cardiac protection, then shift K+)","Send CK isoenzymes to rule out myocardial infarction"], answer:2,
      explanation:"K+ of 6.8 is life-threatening and must be treated first \u2014 give calcium gluconate for cardiac membrane stabilization, then insulin/glucose and albuterol to shift K+ intracellularly. The hypocalcemia should NOT be aggressively corrected (early hypoCa in rhabdo is from Ca deposition in injured muscle \u2014 correcting it can worsen injury). Only treat hypoCa if symptomatic or ECG shows prolonged QT. The heme+ urine with <3 RBCs confirms myoglobinuria.",
      topic: "Rhabdomyolysis" },
    { q:"A 68-year-old man with diffuse atherosclerosis undergoes coronary angiography. His Cr is stable at 1.2 in the first 72 hours. On post-procedure day 10, he presents with Cr 2.6, livedo reticularis on his thighs, and painful blue discoloration of the 2nd and 3rd toes bilaterally despite palpable pedal pulses. CBC shows eosinophils 9%, C3 is mildly low, and UA has a few granular casts without RBC casts. Which finding best distinguishes this from contrast-associated AKI?",
      choices:["Onset 48 hours after contrast","Recovery of Cr to baseline within 7 days","Delayed onset (days to weeks) with peripheral eosinophilia, hypocomplementemia, and livedo","Muddy brown granular casts on urinalysis"], answer:2,
      explanation:"This is atheroembolic (cholesterol crystal embolic) disease. CA-AKI peaks at 48–72 hours and typically recovers within a week; atheroemboli produce a delayed, stepwise/smoldering Cr rise starting 1–4 weeks after an intravascular procedure. The board triad is livedo reticularis, blue-toe syndrome with intact distal pulses, and peripheral eosinophilia (often with transient hypocomplementemia and eosinophiluria). Prognosis is poor — no specific therapy reverses the showered cholesterol crystals; management is statin optimization, BP control, and avoiding repeat instrumentation/anticoagulation when feasible.",
      topic: "Board Challenge" },
  ],
  2: [
    { q:"A 68-year-old with small cell lung cancer is admitted for confusion. Na⁺ 125, serum osm 270, urine osm 450, urine Na 55. She is euvolemic with no edema, normal BP, and no recent diuretics. Most likely diagnosis?",
      choices:["Psychogenic polydipsia","SIADH","Adrenal insufficiency","Beer potomania"], answer:1,
      explanation:"Euvolemic hypotonic hyponatremia with inappropriately concentrated urine (>100) and urine Na >40, after excluding hypothyroidism and adrenal insufficiency, defines SIADH. Small cell lung cancer is a classic paraneoplastic cause via ectopic ADH. Treatment starts with fluid restriction." },
    { q:"A 70-year-old woman with chronic alcohol use is admitted with Na⁺ 108 and seizures. Overnight she receives 3% saline and her Na⁺ rises from 108 to 126 in 18 hours. Two days later she develops dysarthria, dysphagia, and a locked-in-like syndrome. What was the maximum safe correction rate, and what has occurred?",
      choices:["≤6–8 mEq/L in 24h; osmotic demyelination syndrome","≤10–12 mEq/L in 24h; cerebral edema","≤20 mEq/L in 24h; central pontine infarction","No limit; new seizure activity"], answer:0,
      explanation:"In chronic hyponatremia, correction should not exceed 6–8 mEq/L per 24h (stricter in high-risk patients: alcoholism, malnutrition, hypokalemia, liver disease). Too-rapid correction causes osmotic demyelination, a delayed (2–6 day) neurologic syndrome with pseudobulbar and locked-in features. If overcorrection occurs, re-lower with D5W ± DDAVP." },
    { q:"A 58-year-old with ESRD who missed dialysis presents with K⁺ 6.8 and ECG showing peaked T-waves and early QRS widening. What is the FIRST medication to administer?",
      choices:["Insulin + dextrose","Sodium polystyrene sulfonate (Kayexalate)","IV calcium gluconate","Nebulized albuterol"], answer:2,
      explanation:"IV calcium is the first step in any hyperkalemia with ECG changes — it stabilizes the cardiac membrane within minutes. It does NOT lower the K⁺ level; it buys time while insulin/glucose and albuterol shift K⁺ intracellularly and dialysis or diuretics remove it." },
    { q:"A 45-year-old with DKA has ABG pH 7.28, pCO₂ 24, HCO₃⁻ 11, Na⁺ 138, Cl⁻ 100. What is the primary acid-base disorder, and is compensation appropriate?",
      choices:["Respiratory acidosis","Metabolic acidosis with appropriate respiratory compensation","Mixed metabolic and respiratory acidosis","Respiratory alkalosis"], answer:1,
      explanation:"Low pH with low HCO₃⁻ defines metabolic acidosis. Winter's formula: expected pCO₂ = 1.5(HCO₃) + 8 ± 2 = 22.5–26.5; actual pCO₂ of 24 fits, so compensation is appropriate. Anion gap (138 − 100 − 11 = 27) confirms AGMA — consistent with DKA." },
    { q:"A 72-year-old nursing home resident with 5 days of diarrhea is admitted with Na⁺ 128, BP 96/58, dry mucous membranes, and orthostatic vitals. Which is the best initial IV fluid?",
      choices:["D5W","Half-normal saline","Normal saline","3% hypertonic saline"], answer:2,
      explanation:"Hypovolemia triggers non-osmotic ADH release, causing hypotonic hyponatremia. Normal saline restores effective circulating volume → ADH suppression → the kidneys excrete free water and Na⁺ corrects. Reserve 3% saline for severe neurologic symptoms (seizures, obtundation). Monitor correction rate closely; too-rapid correction in these patients risks ODS." },
    { q:"A 30-year-old is brought in after suspected poisoning. ABG shows pH 7.20, HCO₃⁻ 10, anion gap 22. Measured serum osm is 340, Na⁺ 140, BUN 14, glucose 90. Which ingestion does the markedly elevated osmolar gap most suggest?",
      choices:["Aspirin","Methanol or ethylene glycol","Acetaminophen","Iron"], answer:1,
      explanation:"Calculated osm = 2(Na) + BUN/2.8 + glucose/18 ≈ 290. Osmolar gap = 340 − 290 = 50 (normal <10). In a patient with AGMA and an elevated osm gap, suspect toxic alcohols (methanol, ethylene glycol) — they contribute unmeasured osmoles before being metabolized to acid. Start fomepizole and consider dialysis." },
    { q:"A patient with cirrhosis has Na⁺ 124. What is the primary mechanism of hyponatremia?",
      choices:["Renal salt wasting","Decreased ADH clearance by the liver","Effective arterial volume depletion → ADH release","Excess water intake"], answer:2,
      explanation:"In cirrhosis, splanchnic vasodilation → decreased effective arterial volume → non-osmotic ADH release → water retention → dilutional hyponatremia. Treatment is fluid restriction; avoid rapid correction." },
    { q:"A 55-year-old with protracted vomiting from pyloric obstruction has K⁺ 2.9 and HCO₃⁻ 36. Despite aggressive oral KCl repletion, her K⁺ keeps drifting low. Which mechanism best explains why the metabolic alkalosis perpetuates her hypokalemia?",
      choices:["Alkalosis increases renal K⁺ excretion at the collecting duct","The kidney preferentially retains H⁺ instead of K⁺","K⁺ shifts into cells in exchange for H⁺","All of the above"], answer:3,
      explanation:"Alkalosis drives K⁺ intracellularly (H⁺/K⁺ exchange) and increases renal K⁺ secretion (the collecting duct secretes K⁺ while trying to reclaim H⁺). The two disorders sustain each other. You must correct both: give KCl (replaces K⁺ and provides Cl⁻ to restore alkalosis) and treat the underlying volume/chloride deficit." },
    { q:"A 76-year-old hospitalized for cellulitis develops Na⁺ 138, Cl⁻ 114, HCO₃⁻ 18, anion gap 10 after 3 days of high-volume saline infusion and loose stools. Which is the most likely predominant cause of this non-anion gap metabolic acidosis?",
      choices:["Distal (type 1) renal tubular acidosis","GI bicarbonate losses from diarrhea","Saline-induced (hyperchloremic) acidosis from resuscitation fluid","Acetazolamide use"], answer:1,
      explanation:"Both diarrhea and large-volume normal saline cause NAGMA, but diarrhea is the single most common cause overall in hospitalized patients — intestinal fluids are rich in HCO₃⁻. Saline contributes via its supraphysiologic Cl⁻ load (balanced crystalloids like LR reduce this). Urine anion gap can help: negative → GI loss, positive → RTA." },
    { q:"An 82-year-old nursing home patient with dementia presents with Na⁺ 162 and dry mucous membranes after several days of poor oral intake. Regardless of whether his total body Na is low, normal, or high, what is the invariant primary problem in hypernatremia?",
      choices:["Excess sodium intake","A free water deficit relative to sodium","Primary renal sodium retention","Aldosterone excess"], answer:1,
      explanation:"Hypernatremia by definition reflects a free water deficit relative to sodium — a functional water problem, not a salt problem. Calculate the free water deficit: TBW × [(Na/140) − 1]. Replace with D5W or enteral free water, correcting no faster than ~10 mEq/L/24h (or ~0.5 mEq/L/h) to avoid cerebral edema." },
    { q:"A patient with HFrEF (EF 25%) is admitted for decompensated heart failure. On day 3, after receiving IV furosemide 80mg BID with good urine output (3L/day), the Cr rises from 1.2 to 1.6 mg/dL. Weight is down 4 kg, and NT-proBNP has decreased from 8,000 to 3,500. What is the BEST next step?",
      choices:["Stop furosemide due to worsening kidney function","Switch to ultrafiltration","Continue current diuretic regimen — the Cr rise is likely hemodynamic from effective decongestion","Start IV dopamine to improve renal perfusion"], answer:2,
      explanation:"This patient is effectively decongesting (weight down, BNP improving, good UOP). The Cr rise in this context is hemodynamic — not true kidney injury. Stopping diuretics would be a major mistake. CARRESS-HF showed UF is not better than diuretics. Low-dose dopamine has no proven renal benefit. The key teaching point: interpret Cr changes in the CONTEXT of decongestion.",
      topic: "Cardiorenal Syndrome" },
    { q:"In a patient with cardiorenal syndrome and rising creatinine during diuresis, which hemodynamic finding has been shown to be most strongly associated with worsening kidney function?",
      choices:["Low cardiac index","Low systemic blood pressure","Elevated central venous pressure (CVP)","Low pulmonary capillary wedge pressure (PCWP)"], answer:2,
      explanation:"Studies from the ESCAPE trial and others have consistently shown that elevated CVP — not low cardiac output — is the strongest hemodynamic predictor of worsening renal function in HF. Elevated CVP increases renal venous pressure, which directly reduces GFR. This is why venous congestion (not just 'low forward flow') is the primary driver of cardiorenal syndrome.",
      topic: "Cardiorenal Syndrome" },
    { q:"A 58-year-old man with longstanding type 2 diabetes and diabetic neuropathy presents with fatigue and mild muscle weakness. Labs: Na⁺ 138, K⁺ 5.9, Cl⁻ 112, HCO₃⁻ 18, glucose 142, anion gap 8, Cr 1.4 (baseline 1.3), and urine pH 5.1. He takes only metformin. Which disorder best explains this picture?",
      choices:["Type 1 (distal) RTA","Type 2 (proximal) RTA","Type 4 RTA from hyporeninemic hypoaldosteronism","Chronic diarrhea causing non-anion-gap acidosis"], answer:2,
      explanation:"The pattern — hyperkalemic, hyperchloremic, non-anion-gap metabolic acidosis with an appropriately acidic urine (pH <5.5) in a diabetic with mild CKD — is classic Type 4 RTA from hyporeninemic hypoaldosteronism. Unlike Type 1 distal RTA (hypokalemia, urine pH >5.5) and Type 2 proximal RTA (hypokalemia, bicarb wasting, Fanconi features), Type 4 is the only RTA with hyperkalemia. Aldosterone deficiency impairs distal Na⁺/K⁺ and Na⁺/H⁺ exchange; the resulting hyperkalemia suppresses ammoniagenesis, limiting acid excretion despite an ability to acidify the urine. Treatment: loop diuretic and/or fludrocortisone, dietary K⁺ restriction, and discontinuing aggravating drugs (ACEi/ARB, NSAIDs, K⁺-sparing diuretics, TMP/SMX) when possible.",
      topic: "Board Challenge" },
  ],
  3: [
    { q:"A 45-year-old man presents with new bilateral lower-extremity edema and foamy urine. Labs: urine protein 8 g/day, serum albumin 2.1 g/dL, LDL 240, Cr 0.9. UA is bland without RBC casts. Which category best describes his presentation?",
      choices:["Nephritic syndrome","Nephrotic syndrome","CKD stage 4","Acute interstitial nephritis"], answer:1,
      explanation:"Nephrotic syndrome requires heavy proteinuria (>3.5 g/day), hypoalbuminemia, edema, and hyperlipidemia, with a bland sediment. Nephritic syndrome instead features hematuria, dysmorphic RBCs/RBC casts, HTN, and only modest proteinuria. Correctly framing the syndrome drives the biopsy differential (MCD, FSGS, membranous, DKD) vs. a nephritic workup." },
    { q:"A 62-year-old non-diabetic with proteinuric CKD (UACR 900 mg/g, eGFR 38) is already on a max-dose ACE inhibitor. Which medication class has the strongest evidence for slowing CKD progression even in patients without diabetes?",
      choices:["Sulfonylureas","DPP-4 inhibitors","SGLT2 inhibitors","Thiazolidinediones"], answer:2,
      explanation:"SGLT2 inhibitors restore tubuloglomerular feedback → afferent arteriolar constriction → reduced intraglomerular pressure. DAPA-CKD and EMPA-KIDNEY both showed major kidney-endpoint benefit in non-diabetic CKD. They are now a core pillar of proteinuric CKD therapy alongside RAAS blockade, independent of glucose lowering." },
    { q:"A 22-year-old man presents with his second episode of tea-colored urine, occurring on the same day he developed a sore throat. UA shows 3+ blood with dysmorphic RBCs and 1+ protein. C3 and C4 are normal. Most likely diagnosis?",
      choices:["Post-infectious GN","IgA nephropathy","Lupus nephritis","Membranous nephropathy"], answer:1,
      explanation:"Synpharyngitic hematuria (simultaneous with the URI) plus normal complement levels is the signature of IgA nephropathy. Post-infectious GN has a 1–3 week latent period after infection and low C3. Lupus nephritis typically shows low C3 and C4 plus systemic features; membranous presents as nephrotic-range proteinuria, not hematuria." },
    { q:"A 10-year-old boy develops dark 'Coca-Cola' urine, periorbital edema, and BP 150/95 two weeks after a documented strep pharyngitis. Labs show low C3 with normal C4. Most likely diagnosis?",
      choices:["IgA nephropathy","Post-infectious glomerulonephritis","Membranoproliferative GN","Anti-GBM disease"], answer:1,
      explanation:"A 1–3 week latent period after strep plus low C3 with normal C4 (alternative complement pathway activation) is classic for post-infectious GN. IgA would present synpharyngitically with normal complement. MPGN classically has BOTH C3 and C4 low. C3 typically normalizes in 6–8 weeks; treatment is supportive." },
    { q:"A 55-year-old man presents with new nephrotic-range proteinuria and edema. Kidney biopsy shows diffuse thickening of the glomerular basement membrane with subepithelial 'spikes' on silver stain. Which serologic test is most likely to be positive and can help avoid repeat biopsy for monitoring?",
      choices:["Anti-GBM","Anti-PLA2R","ANCA","Anti-dsDNA"], answer:1,
      explanation:"Primary membranous nephropathy is caused by antibodies against the podocyte M-type phospholipase A2 receptor (PLA2R) in ~70% of cases. A positive anti-PLA2R in a classic biopsy picture can substitute for repeat biopsy when assessing treatment response — titer trends correlate with disease activity. Secondary membranous (lupus, hepatitis B, malignancy) is usually PLA2R-negative." },
    { q:"A 28-year-old Black man presents with 4 g/day of proteinuria and edema. Kidney biopsy shows scarring of portions of some glomeruli on light microscopy, with podocyte foot process effacement on EM. Which finding best distinguishes his diagnosis from minimal change disease?",
      choices:["Presence of immune complex deposits","Segmental sclerosis of some glomeruli on light microscopy","Crescent formation","Wire-loop deposits"], answer:1,
      explanation:"Focal segmental glomerulosclerosis (FSGS) shows segmental (part of a glomerulus) sclerosis in a focal (some, not all) distribution on light microscopy. Minimal change disease has normal LM with only podocyte effacement on EM. FSGS is more common in Black adults, is often steroid-resistant, and carries a worse prognosis — APOL1 risk variants help explain the epidemiology." },
    { q:"A 68-year-old woman with long-standing hypertension has an eGFR of 24 mL/min/1.73m² (confirmed on two visits, 3 months apart). She has mild albuminuria. Which CKD G stage and clinical milestone does she meet?",
      choices:["G3a — initiate metformin","G3b — dose-adjust medications only","G4 — begin education about renal replacement options","G5 — start dialysis now"], answer:2,
      explanation:"KDIGO G-stages: G1 ≥90, G2 60–89, G3a 45–59, G3b 30–44, G4 15–29, G5 <15. eGFR 24 = G4. This is the stage at which education about transplant, dialysis modalities, and advance care planning should begin — not waiting until G5. Vascular access planning and transplant referral (if eGFR ≤20) are also time-sensitive milestones." },
    { q:"In the United States, which of the following is the single most common cause of nephrotic-range proteinuria when all etiologies are considered together?",
      choices:["Minimal change disease","Membranous nephropathy","Diabetic nephropathy","FSGS"], answer:2,
      explanation:"Diabetic nephropathy dominates the epidemiology of nephrotic-range proteinuria because of the sheer prevalence of diabetes. Among PRIMARY glomerular diseases, membranous is most common in white adults and FSGS is most common in Black adults. On boards, read the stem carefully — 'overall' vs. 'primary glomerular' changes the answer." },
    { q:"A 64-year-old with hypertension has a Cr of 3.2 and no prior baseline. Which renal ultrasound finding most strongly supports chronic kidney disease rather than AKI?",
      choices:["Hydronephrosis","Bilateral small (<9 cm) kidneys","Normal-sized kidneys","Increased cortical echogenicity alone"], answer:1,
      explanation:"Bilaterally small kidneys indicate long-standing parenchymal loss and strongly suggest CKD — these will not recover. Increased echogenicity is nonspecific and seen in both AKI and CKD. One important exception: diabetic nephropathy and amyloidosis can present with normal-sized or even large kidneys despite advanced CKD, so size alone is not sufficient." },
    { q:"A 58-year-old with diabetic kidney disease on max-dose lisinopril is seen by an outside provider who adds losartan for 'better renal protection.' Two weeks later she presents with K⁺ 6.3 and Cr up from 1.6 to 2.4. Why is dual RAAS blockade contraindicated?",
      choices:["ACEi and ARB cancel each other's effects","Dual RAAS blockade increases risk of hyperkalemia, AKI, and hypotension without added benefit","ARBs are always inferior to ACEi","They share the same hepatic metabolic pathway"], answer:1,
      explanation:"ONTARGET and VA NEPHRON-D both showed that combining an ACEi with an ARB produces more hyperkalemia, AKI, and hypotension without reducing kidney or cardiovascular endpoints. Use one or the other — not both. Modern layering of kidney protection in proteinuric CKD is ACEi/ARB + SGLT2i + (for DKD) finerenone." },
    { q:"A 52-year-old with type 2 diabetes (15 years), diabetic retinopathy, and eGFR 35 has a UACR of 450 mg/g. She is on max-dose lisinopril. Her UA is bland. Which medication should be added NEXT based on current evidence?",
      choices:["Spironolactone","SGLT2 inhibitor (dapagliflozin or empagliflozin)","Hydrochlorothiazide for additional BP control","Amlodipine"], answer:1,
      explanation:"An SGLT2i is the next step — it's the second pillar of DKD therapy. DAPA-CKD and EMPA-KIDNEY showed major kidney and CV benefit, including in patients with eGFR as low as 20. After SGLT2i, consider adding finerenone (3rd pillar, per FIDELIO-DKD). Spironolactone has more hyperkalemia risk and less kidney outcome data than finerenone for DKD.",
      topic: "Diabetic Kidney Disease" },
    { q:"A patient with CKD (eGFR 42) is started on dapagliflozin. Two weeks later, eGFR has dropped from 42 to 37 mL/min. The patient feels well. What should you do?",
      choices:["Stop dapagliflozin — this represents acute kidney injury","Switch to a different SGLT2 inhibitor","Continue dapagliflozin — this initial eGFR dip is expected and reflects hemodynamic changes, not injury","Add IV fluids to counteract volume depletion"], answer:2,
      explanation:"An initial eGFR dip of 3-5 mL/min is expected when starting an SGLT2i. This reflects reduced intraglomerular pressure from restored tubuloglomerular feedback — the same mechanism that provides long-term kidney protection (similar to the ACEi/ARB dip). The eGFR typically stabilizes or rebounds by 3 months. Stopping the drug would deprive the patient of its protective effects.",
      topic: "SGLT2 Inhibitors" },
    { q:"Which of the following findings in a diabetic patient with proteinuria would make you MOST concerned that their kidney disease is NOT diabetic kidney disease?",
      choices:["UACR of 500 mg/g","Presence of diabetic retinopathy","Active urine sediment with dysmorphic RBCs and RBC casts","eGFR decline of 3 mL/min/year over 3 years"], answer:2,
      explanation:"Active sediment with dysmorphic RBCs and RBC casts indicates glomerulonephritis — NOT DKD. DKD characteristically has a bland sediment. This patient needs a kidney biopsy to identify the true diagnosis. Other red flags for non-DKD: no retinopathy, rapid GFR decline, onset <5 years after T1DM diagnosis, or nephritic features.",
      topic: "Diabetic Kidney Disease" },
    { q:"A 52-year-old woman with type 2 diabetes (eGFR 42, UACR 620 mg/g) on maximally tolerated lisinopril and empagliflozin has a K⁺ of 4.6 and clinic BP 132/78. Her HbA1c is 7.2%. She has no history of heart failure. Based on the FIDELIO-DKD and FIGARO-DKD trials, what is the best next step to further reduce her risk of CKD progression and CV events?",
      choices:["Add spironolactone 25 mg daily","Add finerenone 10 mg daily","Switch lisinopril to an ARB for better outcomes","Add a DPP-4 inhibitor"], answer:1,
      explanation:"Finerenone is the KDIGO-endorsed third pillar of DKD therapy after RAAS blockade and SGLT2i. FIDELIO-DKD and FIGARO-DKD (pooled as FIDELITY) showed that finerenone reduces kidney and CV composite endpoints by ~13–18% on top of a maximally tolerated ACEi/ARB. Unlike the steroidal MRA spironolactone, the nonsteroidal MRA finerenone has a more favorable K⁺ profile and dedicated CKD outcome data; eligibility in the trials required eGFR ≥25 and K⁺ ≤4.8 (start 10 mg if eGFR 25–59, 20 mg if ≥60). Monitor K⁺ 4 weeks after initiation and after each up-titration.",
      topic: "Board Challenge" },
  ],
  4: [
    { q:"A 66-year-old with AKI has Cr 7.4, K⁺ 5.8, pH 7.28, and volume overload with pulmonary edema on exam. She is also confused with asterixis. Which mnemonic captures the standard indications that led you to call for urgent dialysis?",
      choices:["MUDPILES","AEIOU","HARDUP","CRASH"], answer:1,
      explanation:"AEIOU = Acidosis (refractory), Electrolytes (refractory, usually K⁺), Ingestions (dialyzable toxins), Overload (refractory), Uremia (pericarditis, encephalopathy, bleeding). This patient has O + U at minimum. MUDPILES is the anion-gap acidosis mnemonic. Don't wait for a single 'dangerous number' — any AEIOU indication can justify RRT." },
    { q:"A 72-year-old with CHF on chronic furosemide develops K⁺ 3.0, metabolic alkalosis, and muscle cramps. The diuretic's mechanism is best described as blockade of which transporter, at which nephron segment?",
      choices:["ENaC in the collecting duct","NKCC2 in the thick ascending limb","NCC in the distal convoluted tubule","Na⁺/H⁺ exchanger in the proximal tubule"], answer:1,
      explanation:"Loop diuretics block NKCC2 in the thick ascending limb, where ~25% of filtered Na⁺ is normally reabsorbed — making them the most potent diuretics. The resulting increased distal Na⁺ delivery drives K⁺ and H⁺ secretion in the collecting duct, producing hypokalemia and contraction alkalosis. Knowing the segment lets you predict the electrolyte panel." },
    { q:"A patient admitted with HSV encephalitis is started on high-dose IV acyclovir. Forty-eight hours later, Cr has risen from 0.9 to 2.2 and urine microscopy shows needle-shaped birefringent crystals. Which drug most classically causes this pattern of AKI?",
      choices:["Metformin","Acyclovir","Lisinopril","Metoprolol"], answer:1,
      explanation:"Acyclovir precipitates in the tubular lumen when urine flow is low or the drug bolus is concentrated — producing crystal nephropathy with birefringent needle-shaped crystals. Prevention is volume-dependent: isotonic IV hydration and slower infusion (≥1 hour). Other classic crystal-forming agents: methotrexate, sulfonamides, indinavir/atazanavir, and high-dose IV vitamin C." },
    { q:"A 58-year-old woman started on a new antihypertensive develops Na⁺ 128, K⁺ 3.1, Ca²⁺ 10.6, and uric acid 9.0. The drug acts at which segment, and these side effects are classic for which class?",
      choices:["Thick ascending limb; loop diuretic","Distal convoluted tubule; thiazide diuretic","Collecting duct; K⁺-sparing diuretic","Proximal tubule; carbonic anhydrase inhibitor"], answer:1,
      explanation:"Thiazides block NCC in the DCT. Their signature side-effect cluster is hyponatremia, hypokalemia, HYPERcalcemia (enhanced distal Ca²⁺ reabsorption — opposite of loops), hyperuricemia, and hyperglycemia. Useful clinical pearl: a patient with hypercalcemia of unclear cause should have thiazides stopped before further workup." },
    { q:"A hemodynamically fragile 78-year-old with severe CHF and recurrent intradialytic hypotension is being counseled about dialysis modality. Which is the most important advantage of peritoneal dialysis over conventional in-center hemodialysis for this patient?",
      choices:["Faster per-session solute clearance","Gentler continuous clearance with better hemodynamic stability, done at home","Higher Kt/V per session","Better suited for very large body habitus"], answer:1,
      explanation:"PD provides slow, continuous solute and fluid removal — resulting in more stable blood pressures and fewer intradialytic hypotension events compared to thrice-weekly HD. It is also home-based, which preserves residual kidney function longer and supports patient independence. HD clears solutes faster per session but at the cost of rapid volume/osmolar shifts." },
    { q:"A kidney transplant recipient develops BK viremia 6 months post-transplant. Best initial management?",
      choices:["Start antivirals","Reduce immunosuppression","Increase immunosuppression","Emergent transplant nephrectomy"], answer:1,
      explanation:"BK is an opportunistic polyomavirus. First-line management is carefully stepwise reduction of immunosuppression (typically MMF first, then CNI) to restore T-cell immunity \u2014 this is the only intervention with consistent evidence. Surveillance is the cornerstone: the 2024 international BK consensus (endorsed by AST-IDCOP) updated screening to monthly plasma BK PCR through month 9, then every 3 months through year 2, with action thresholds around plasma viral loads >10,000 copies/mL (older guidance stopped monthly screening at 6 months). No dedicated antiviral is effective; IVIG has supportive (non-RCT) data for persistent viremia or biopsy-proven BKVAN at some centers. Leflunomide and cidofovir are generally discouraged due to toxicity without clear benefit. BKVAN is still possible beyond 12 months \u2014 don't rule it out by timing alone." },
    { q:"A 42-year-old man with acute flank pain is found on non-contrast CT to have a 6-mm ureteric stone. A plain abdominal X-ray (KUB) performed in the ER did NOT show the stone. Which stone composition is most consistent with this imaging pattern?",
      choices:["Calcium oxalate","Struvite","Uric acid","Calcium phosphate"], answer:2,
      explanation:"Uric acid stones are radiolucent on plain X-ray but readily visible on non-contrast CT — the gold standard for stone imaging. Uric acid stones form in persistently acidic urine (pH <5.5) and can often be dissolved with urinary alkalinization (potassium citrate), targeting urine pH ~6.5. Calcium, struvite, and cystine stones are all radio-opaque on KUB." },
    { q:"A patient hospitalized for decompensated heart failure is 'diuretic resistant' on escalating IV furosemide. Her team adds oral metolazone, and UOP markedly increases. What is the mechanism of this synergy?",
      choices:["It blocks the same NKCC2 transporter as loops for additive effect","It blocks compensatory Na⁺ reabsorption at the NCC in the DCT","It directly increases GFR","It acts as an osmotic diuretic"], answer:1,
      explanation:"Chronic loop use drives distal nephron hypertrophy and increased Na⁺ reabsorption at the DCT — braking the diuretic response. Thiazide-type agents like metolazone block NCC in the DCT, producing sequential nephron blockade and powerful synergy. Watch closely for hypokalemia, hyponatremia, and rapid volume depletion when starting this combination." },
    { q:"A 62-year-old man hospitalized for pneumonia and treated with ceftriaxone and a PPI develops AKI on day 7 with Cr 1.0 → 2.6. He has a new maculopapular rash and low-grade fever. UA shows WBC casts and sterile pyuria; peripheral eosinophil count is elevated. What is the most likely diagnosis and its classic triad?",
      choices:["Pre-renal AKI; hematuria, proteinuria, HTN","Acute interstitial nephritis; fever, rash, eosinophilia","Nephrotic syndrome; oliguria, edema, HTN","Renal cell carcinoma; flank pain, hematuria, mass"], answer:1,
      explanation:"AIN classically presents with fever, rash, and peripheral eosinophilia, though the complete triad is seen in only ~10–30% of cases. Urine typically shows WBC casts and sterile pyuria (eosinophiluria is insensitive). Common triggers: antibiotics (beta-lactams, sulfas), PPIs, and NSAIDs. Management: stop the offending drug; steroids are considered if AKI does not resolve." },
    { q:"A 76-year-old man with MRSA bacteremia is being treated with IV vancomycin. On hospital day 5, his Cr rises from 0.9 to 1.5. Which monitoring strategy is used specifically to balance efficacy against nephrotoxicity for this drug?",
      choices:["Serum metformin level","Vancomycin trough level or AUC/MIC targeting","Serum amoxicillin level","Acetaminophen level"], answer:1,
      explanation:"Vancomycin can cause AKI through direct proximal tubular toxicity and (less commonly) AIN. Modern guidelines (IDSA/ASHP 2020) favor AUC/MIC targeting of 400–600 mg·h/L over trough-only monitoring, which reduces nephrotoxicity while preserving efficacy. Avoidance of concomitant nephrotoxins (especially piperacillin-tazobactam) is also important." },
    { q:"A PD patient presents with cloudy effluent, mild abdominal pain, and low-grade fever. The effluent WBC is 450/\u03bcL with 85% PMNs. Gram stain shows gram-positive cocci in clusters. What is the BEST initial antibiotic regimen?",
      choices:["IV vancomycin + IV piperacillin-tazobactam","Intraperitoneal (IP) vancomycin + IP gentamicin","Oral ciprofloxacin + oral metronidazole","IV cefazolin monotherapy"], answer:1,
      explanation:"ISPD 2022 empiric therapy is center-specific and must cover BOTH gram-positive and gram-negative organisms intraperitoneally: (a) first-generation cephalosporin OR vancomycin for gram-positive cover, PLUS (b) a third-generation cephalosporin (eg, ceftazidime) OR an aminoglycoside (eg, gentamicin) for gram-negative cover; IP cefepime monotherapy is also acceptable. Pick based on local sensitivities, MRSA prevalence, and prior cultures. IP dosing is essential \u2014 IV antibiotics alone do NOT achieve adequate peritoneal concentrations. Effluent WBC >100/\u03bcL with >50% PMNs (after a dwell time of at least 2 hours) confirms peritonitis. The gram-positive cocci suggest S. aureus or S. epidermidis; tailor antibiotics when cultures return.",
      topic: "Peritoneal Dialysis" },
    { q:"During treatment of PD peritonitis with appropriate IP antibiotics, the effluent remains cloudy and WBC count remains elevated on day 5. Cultures grew Candida albicans. What is the next step?",
      choices:["Continue current antibiotics for a total of 21 days","Add IP fluconazole to the current regimen","Remove the PD catheter and transition to temporary HD","Increase the dwell volume to improve antibiotic delivery"], answer:2,
      explanation:"Fungal peritonitis is an absolute indication for PD catheter removal per ISPD guidelines. Fungal peritonitis has very poor outcomes with catheter retention, and antifungal antibiotics alone are insufficient. The patient should have the catheter removed, receive systemic antifungal therapy, and transition to hemodialysis (via temporary HD catheter). PD may be resumed later with a new catheter after adequate treatment.",
      topic: "Peritoneal Dialysis" },
    { q:"A 62-year-old man with HFrEF (EF 20%) and CKD (baseline Cr 1.8) is admitted with decompensated HF. He receives IV furosemide 160 mg BID but net urine output is only 600 mL/day after 48 hours despite persistent JVD, 3+ lower-extremity edema, and weight unchanged. A spot urine Na⁺ 2 hours after the furosemide dose is 18 mEq/L. Which intervention best addresses the physiologic mechanism of his diuretic resistance?",
      choices:["Increase the furosemide infusion and add IV dopamine for renal perfusion","Add oral metolazone 30 minutes before the loop dose to block compensatory distal sodium reabsorption","Switch to IV bumetanide at an equipotent dose","Start ultrafiltration because CARRESS-HF favors UF over diuretics"], answer:1,
      explanation:"A post-loop urine Na⁺ <50–70 mEq/L with inadequate diuresis despite high-dose IV loop diuretic defines 'braking' — chronic loop exposure causes hypertrophy of the DCT (distal convoluted tubule) with compensatory upregulation of the NCC cotransporter, so the Na⁺ the loop would have shed is reclaimed downstream. Sequential nephron blockade with a thiazide-type agent (metolazone, chlorothiazide, or HCTZ) given 30 minutes before the loop dose blocks NCC and restores natriuresis. Simply escalating the loop or switching to an equipotent agent does not overcome the distal compensation. CARRESS-HF showed stepped pharmacologic therapy was superior to UF in cardiorenal syndrome. Low-dose dopamine (ROSE-AHF) provided no renal benefit. Monitor K⁺, Mg²⁺, and volume closely with combination diuretics.",
      topic: "Board Challenge" },
  ],
};

