// ═══════════════════════════════════════════════════════════════════════
//  Helper: Resolve a question key to its question object (for spaced repetition)
//  Keys: "weekly_1_0", "pre_2_3", "post_4_1", "topicrf_aki_0", etc.
// ═══════════════════════════════════════════════════════════════════════

export function topicToSlug(topic: string): string {
  return topic.toLowerCase().replace(/\s+/g, "-");
}

export function buildTopicReinforcementKey(topic: string, idx: number): string {
  return `topicrf_${topicToSlug(topic)}_${idx}`;
}

export function getQuestionByKey(key) {
  const parts = key.split("_");
  const source = parts[0];
  if (source === "topicrf") {
    // Format: topicrf_<slug>_<idx>. Slug may contain hyphens (no underscores).
    const slug = parts[1];
    const idx = parseInt(parts[2]);
    if (isNaN(idx)) return null;
    const topic = Object.keys(TOPIC_REINFORCEMENT_BANK).find((t) => topicToSlug(t) === slug);
    return topic ? (TOPIC_REINFORCEMENT_BANK[topic]?.[idx] || null) : null;
  }
  const week = parseInt(parts[1]);
  const idx = parseInt(parts[2]);
  if (isNaN(week) || isNaN(idx)) return null;
  if (source === "weekly") return WEEKLY_QUIZZES[week]?.[idx] || null;
  // week === 0 means the flat pre/post array was used (assessments pass week=0)
  if (source === "pre") return week === 0 ? (PRE_QUIZ[idx] || null) : (PRE_QUIZ_BY_WEEK[week]?.[idx] || null);
  if (source === "post") return week === 0 ? (POST_QUIZ[idx] || null) : (POST_QUIZ_BY_WEEK[week]?.[idx] || null);
  return null;
}
